/** PDF demo embebido para PDF.js (generado; fuente: guia-mapa-conflicto.pdf). */
(function (g) {
    var B64 = "";
    var cache;
    g.CC_DEMO_PDF_GET_ARRAY_BUFFER = function () {
        if (cache) return cache;
        var bin = atob(B64);
        var u8 = new Uint8Array(bin.length);
        for (var i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
        cache = u8.buffer;
        return cache;
    };
})(typeof window !== "undefined" ? window : this);
